import java.util.*;class CustomHashMap{static class Node{int k,v;Node next;Node(int k,int v){this.k=k;this.v=v;}}static int size=10;static Node[] table=new Node[size];static int hash(int k){return k%size;}static void put(int k,int v){int i=hash(k);Node n=new Node(k,v);if(table[i]==null)table[i]=n;else{Node c=table[i];while(c.next!=null)c=c.next;c.next=n;}}static int get(int k){int i=hash(k);Node c=table[i];while(c!=null){if(c.k==k)return c.v;c=c.next;}return -1;}public static void main(String[]a){put(1,10);put(11,20);System.out.println(get(11));}}